mapper.select:
SELECT EXISTS (
	SELECT 1
	FROM users
	WHERE nickname = #{nickname}
		AND id != #{userId}
)

mapper.update:
UPDATE users
SET profile_image_url = #{profileImageUrl}
WHERE id = #{userId}
	AND status = 'ACTIVE'

UPDATE users
SET status = 'DELETED'
WHERE id = #{userId}

UPDATE users
SET password = #{encodedPassword}
WHERE id = #{userId}
	AND status = 'ACTIVE'
	AND provider = 'LOCAL'

mapper.select:
SELECT s.id AS spotId, s.experience, s.name AS spotName, s.lat, s.lng, s.region, mf.forecast_date AS forecastDate, mf.time_slot AS timeSlot, mf.total_index AS totalIndex, s.post_count AS postCount, TRUE AS favorite, CAST(mf.metrics AS CHAR) AS metrics FROM favorite_spots fs JOIN spots s ON s.id = fs.spot_id LEFT JOIN marine_forecasts mf ON mf.spot_id = s.id AND mf.forecast_date = #{targetDate} AND mf.id = ( SELECT mf2.id FROM marine_forecasts mf2 WHERE mf2.spot_id = s.id AND mf2.forecast_date = #{targetDate}
AND mf2.time_slot = #{timeSlot}
ORDER BY mf2.time_slot ASC, mf2.id ASC LIMIT 1 ) WHERE fs.user_id = #{userId} AND s.active = 1
AND mf.id IS NOT NULL
ORDER BY fs.created_at DESC, fs.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM favorite_spots fs
JOIN spots s ON s.id = fs.spot_id
WHERE fs.user_id = #{userId}
	AND s.active = 1

	AND EXISTS (
		SELECT 1
		FROM marine_forecasts mf
		WHERE mf.spot_id = s.id
			AND mf.forecast_date = #{targetDate}
			AND mf.time_slot = #{timeSlot}
	)
